import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import {
  Compass,
  Package,
  Users,
  Truck,
  FileText,
  BarChart3,
  Settings,
  Fuel,
  Wrench,
  ChevronLeft,
  ChevronRight,
  LogOut
} from 'lucide-react';
import { useLogisticsStore } from '@/lib/logistics/store';

interface SidebarProps {
  isOpen: boolean;
  onClose: () => void;
}

export default function Sidebar({ isOpen, onClose }: SidebarProps) {
  const pathname = usePathname();
  const { sidebarCollapsed, setSidebarCollapsed } = useLogisticsStore();

  const NAV_ITEMS = [
    { href: '/logistics/tracking', icon: Compass, label: 'Live Tracking' },
    { href: '/logistics/loads', icon: Package, label: 'Loads' },
    { href: '/logistics/drivers', icon: Users, label: 'Drivers' },
    { href: '/logistics/vehicles', icon: Truck, label: 'Fleet & Assets' },
    { href: '/logistics/fuel', icon: Fuel, label: 'Fuel Expenses' },
    { href: '/logistics/maintenance', icon: Wrench, label: 'Maintenance' },
    { href: '/logistics/invoices', icon: FileText, label: 'Client Invoices' },
    { href: '/logistics/analytics', icon: BarChart3, label: 'Analytics' },
    { href: '/logistics/settings', icon: Settings, label: 'Settings' },
  ];

  const isActive = (href: string) => pathname === href || pathname.startsWith(href + '/');

  return (
    <>
      {/* Sidebar background drawer on mobile */}
      {isOpen && (
        <div
          onClick={onClose}
          className="fixed inset-0 z-40 bg-slate-900/60 lg:hidden backdrop-blur-sm"
        />
      )}

      <aside
        className={`fixed top-0 bottom-0 left-0 z-50 flex flex-col bg-slate-900 text-slate-100 border-r border-slate-800 transition-all duration-300
          ${isOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
          ${sidebarCollapsed ? 'w-20' : 'w-64'}
        `}
      >
        {/* Header/Logo */}
        <div className="flex items-center justify-between h-16 px-4 border-b border-slate-800">
          <Link href="/logistics/tracking" className="flex items-center gap-3 font-semibold overflow-hidden">
            <div className="flex items-center justify-center w-10 h-10 rounded-xl bg-blue-600 shadow-md shadow-blue-500/25 shrink-0">
              <Truck size={20} className="text-white" />
            </div>
            {!sidebarCollapsed && (
              <div className="flex flex-col">
                <span className="text-base font-bold tracking-tight text-white leading-none">LoadSwift</span>
                <span className="text-[10px] text-slate-400 font-medium mt-1 uppercase tracking-wider">Logistics ERP</span>
              </div>
            )}
          </Link>
          <button
            onClick={() => setSidebarCollapsed(!sidebarCollapsed)}
            className="hidden lg:flex items-center justify-center w-7 h-7 rounded-lg hover:bg-slate-850 text-slate-400 hover:text-white"
          >
            {sidebarCollapsed ? <ChevronRight size={16} /> : <ChevronLeft size={16} />}
          </button>
        </div>

        {/* Navigation Items */}
        <nav className="flex-1 px-3 py-4 space-y-1 overflow-y-auto no-scrollbar">
          {NAV_ITEMS.map((item) => {
            const active = isActive(item.href);
            const Icon = item.icon;
            return (
              <Link
                key={item.href}
                href={item.href}
                onClick={() => onClose()}
                className={`flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all group relative
                  ${active
                    ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/10'
                    : 'text-slate-450 hover:bg-slate-800 hover:text-white'
                  }
                  ${sidebarCollapsed ? 'justify-center' : ''}
                `}
                title={sidebarCollapsed ? item.label : undefined}
              >
                <Icon size={18} className={active ? 'text-white' : 'text-slate-400 group-hover:text-white'} />
                {!sidebarCollapsed && <span>{item.label}</span>}
                {sidebarCollapsed && (
                  <span className="absolute left-full ml-4 px-2.5 py-1.5 bg-slate-950 text-slate-100 text-xs font-semibold rounded-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all whitespace-nowrap z-50 shadow-md border border-slate-850">
                    {item.label}
                  </span>
                )}
              </Link>
            );
          })}
        </nav>

        {/* Footer actions: ERP return */}
        <div className="p-3 border-t border-slate-800 bg-slate-950/40">
          <Link
            href="/companies"
            className={`flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium text-slate-400 hover:bg-slate-800 hover:text-rose-450 transition-all group relative
              ${sidebarCollapsed ? 'justify-center' : ''}
            `}
            title={sidebarCollapsed ? 'Back to ERP' : undefined}
          >
            <LogOut size={18} className="text-slate-400 group-hover:text-rose-400 rotate-180" />
            {!sidebarCollapsed && <span>Return to ERP Suite</span>}
            {sidebarCollapsed && (
              <span className="absolute left-full ml-4 px-2.5 py-1.5 bg-slate-950 text-slate-100 text-xs font-semibold rounded-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all whitespace-nowrap z-50 shadow-md border border-slate-850">
                Return to ERP Suite
              </span>
            )}
          </Link>
        </div>
      </aside>
    </>
  );
}
