import React, { useState } from 'react';
import { Menu, Bell, RefreshCw, Plus, CheckCircle, Database } from 'lucide-react';
import { useStore, useActiveCompany } from '@/lib/store';
import toast from 'react-hot-toast';

interface TopBarProps {
  onMenuOpen: () => void;
  title: string;
}

export default function TopBar({ onMenuOpen, title }: TopBarProps) {
  const company = useActiveCompany();
  const { user } = useStore();
  const [isSeeding, setIsSeeding] = useState(false);

  const triggerSeed = async () => {
    if (!company?.id) {
      toast.error('No active company selected');
      return;
    }

    if (!confirm('Are you sure you want to seed logistics demo data? This will clear any existing LoadSwift records for this company and replace them with fresh realistic demo data.')) {
      return;
    }

    setIsSeeding(true);
    const toastId = toast.loading('Seeding realistic logistics demo data...');
    try {
      const res = await fetch('/api/logistics/seed', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ companyId: company.id })
      });

      if (!res.ok) {
        throw new Error('Seed request failed');
      }

      toast.success('Logistics demo data seeded! Refreshing page...', { id: toastId });
      setTimeout(() => {
        window.location.reload();
      }, 1000);
    } catch (err: any) {
      toast.error(`Error: ${err.message}`, { id: toastId });
    } finally {
      setIsSeeding(false);
    }
  };

  return (
    <header className="sticky top-0 z-30 flex items-center justify-between h-16 px-4 bg-white border-b border-slate-200 shadow-sm dark:bg-slate-900 dark:border-slate-800">
      <div className="flex items-center gap-3">
        {/* Mobile menu trigger */}
        <button
          onClick={onMenuOpen}
          className="p-2 -ml-2 rounded-lg lg:hidden hover:bg-slate-100 text-slate-600 dark:text-slate-400 dark:hover:bg-slate-800"
        >
          <Menu size={20} />
        </button>

        {/* Title */}
        <h1 className="text-lg font-bold text-slate-900 dark:text-white">{title}</h1>
      </div>

      <div className="flex items-center gap-4">
        {/* Demo Data Seeder Button */}
        <button
          onClick={triggerSeed}
          disabled={isSeeding}
          className={`flex items-center gap-2 px-3 py-1.5 text-xs font-semibold rounded-lg text-white bg-indigo-600 hover:bg-indigo-700 shadow-sm transition-all disabled:opacity-50
            ${isSeeding ? 'animate-pulse' : ''}
          `}
          title="Seed realistic logistics mock data"
        >
          <Database size={14} />
          <span>{isSeeding ? 'Seeding...' : 'Seed Demo Data'}</span>
        </button>

        {/* Active Company Badge */}
        {company && (
          <div className="hidden sm:flex items-center gap-2 px-3 py-1 bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-full">
            <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
            <span className="text-xs font-semibold text-slate-750 dark:text-slate-300 max-w-[140px] truncate">
              {company.name}
            </span>
          </div>
        )}

        {/* Notifications Icon */}
        <button className="p-2 text-slate-500 dark:text-slate-450 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg relative">
          <Bell size={20} />
          <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-rose-500 rounded-full border border-white dark:border-slate-900" />
        </button>

        {/* User profile / Avatar */}
        <div className="flex items-center gap-2 border-l border-slate-200 dark:border-slate-850 pl-4">
          <div className="flex flex-col text-right hidden md:flex">
            <span className="text-xs font-semibold text-slate-900 dark:text-white leading-none">
              {user?.name || 'Dispatcher'}
            </span>
            <span className="text-[10px] text-slate-400 font-medium mt-0.5 capitalize">
              {user?.role?.replace('_', ' ') || 'Admin'}
            </span>
          </div>
          <div className="w-9 h-9 rounded-full bg-blue-100 text-blue-800 dark:bg-blue-900/50 dark:text-blue-200 flex items-center justify-center font-bold text-sm">
            {(user?.name || 'D')[0].toUpperCase()}
          </div>
        </div>
      </div>
    </header>
  );
}
